const express = require('express');
const { Storage } = require('@google-cloud/storage');

const app = express();
const storage = new Storage();

app.get('/files/:bucket/:path', async (req, res) => {
  const bucketName = req.params.bucket;
  const filePath = normalizePath(req.params.path);

  try {
    const options = {
      destination: res
    };

    await storage.bucket(bucketName).file(filePath).download(options);
    res.status(200).send();
  } catch (err) {
    console.error(err);
    res.status(500).send('Error retrieving file');
  }
});

function normalizePath(path) {
  return path.split('/').filter(part => part !== '').join('/');
}

exports.fileServingAPI = functions.https.onCall(app);